# Definition for a binary tree node.
class TreeNode:
    def __init__(self, x: int):
        self.val = x
        self.left = None
        self.right = None

class Solution:
    def removeSubtrees(self, root: TreeNode, queries: List[int]) -> List[int]:
        def removeSubtree(node: TreeNode, val: int):
            if not node: return

            if node.left and node.left.val == val:
                node.left = None
            else:
                removeSubtree(node.left, val)

            if node.right and node.right.val == val:
                node.right = None
            else:
                removeSubtree(node.right, val)

        def findHeight(node: TreeNode) -> int:
            if not node: return -1

            return 1 + max(findHeight(node.left), findHeight(node.right))

        answer = []
        for query in queries:
            removeSubtree(root, query)
            answer.append(findHeight(root))

        return answer
```

    The algorithm works as follows:
1. Iterate through the queries independently - for each query:
   a. Call the `removeSubtree` function, which searches for the node with the value equal to the current query and sets its reference in the parent node to null.
   b. Call the `findHeight` function, which calculates the height of the (modified) tree using a recursive approach.
   c. Add the height of the (modified) tree to the `answer` list/array.
2. Return the `answer` list/array.

