// Definition for a binary tree node.
public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode() {}
    TreeNode(int val) { this.val = val; }
    TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

class Solution {
    public int[] removeSubtrees(TreeNode root, int[] queries) {
        int[] answer = new int[queries.length];

        for (int i = 0; i < queries.length; ++i) {
            removeSubtree(root, queries[i]);
            answer[i] = findHeight(root);
        }

        return answer;
    }

    public void removeSubtree(TreeNode node, int val) {
        if (node == null) return;

        if (node.left != null && node.left.val == val)
            node.left = null;
        else
            removeSubtree(node.left, val);

        if (node.right != null && node.right.val == val)
            node.right = null;
        else
            removeSubtree(node.right, val);
    }

    public int findHeight(TreeNode node) {
        if (node == null) return -1;

        return 1 + Math.max(findHeight(node.left), findHeight(node.right));
    }
}
